+    agentsRef,
+    byNormalizedId,
+    fallbackDefaultAgentId: sanitizeAgentId(resolveDefaultAgentId(cfg)),
+  };
+  agentLookupCacheByCfg.set(cfg, next);
+  return next;
+}
